import{_ as a,c as r,o as l,a1 as i}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"プライバシーポリシー: データ保護について | OpenCodeDocs","description":"OpenCodeDocs のプライバシーポリシーとデータ保護措置について。個人情報の収集、使用、保存方法、およびデータに関する権利について説明します。","frontmatter":{"title":"プライバシーポリシー: データ保護について | OpenCodeDocs","sidebarTitle":"あなたのデータはどこへ","subtitle":"プライバシーポリシー: データ保護について","description":"OpenCodeDocs のプライバシーポリシーとデータ保護措置について。個人情報の収集、使用、保存方法、およびデータに関する権利について説明します。"},"headers":[],"relativePath":"ja/privacy.md","filePath":"ja/privacy.md"}'),t={name:"ja/privacy.md"};function e(n,o,s,g,h,c){return l(),r("div",null,[...o[0]||(o[0]=[i('<h1 id="プライバシーポリシー" tabindex="-1">プライバシーポリシー <a class="header-anchor" href="#プライバシーポリシー" aria-label="Permalink to &quot;プライバシーポリシー&quot;">​</a></h1><p>最終更新日：2026-01-01</p><p>OpenCodeDocs をご利用いただき、ありがとうございます。お客様のプライバシーと個人情報の保護を重視しています。本プライバシーポリシーでは、個人情報の収集、使用、保存、保護について説明します。</p><h2 id="_1-収集する情報" tabindex="-1">1. 収集する情報 <a class="header-anchor" href="#_1-収集する情報" aria-label="Permalink to &quot;1. 収集する情報&quot;">​</a></h2><p>OpenCodeDocs サービスをご利用いただく際、以下の情報を収集する場合があります。</p><h3 id="アカウント情報" tabindex="-1">アカウント情報 <a class="header-anchor" href="#アカウント情報" aria-label="Permalink to &quot;アカウント情報&quot;">​</a></h3><ul><li><strong>メールアドレス</strong>：アカウント登録、ログイン認証、重要な通知の送信に使用します</li><li><strong>ユーザー名</strong>：お客様が選択した表示名</li><li><strong>GitHub アカウント情報</strong>：GitHub ログインを選択した場合、公開情報を取得します</li></ul><h3 id="使用データ" tabindex="-1">使用データ <a class="header-anchor" href="#使用データ" aria-label="Permalink to &quot;使用データ&quot;">​</a></h3><ul><li><strong>閲覧履歴</strong>：アクセスしたチュートリアルページと時刻</li><li><strong>インタラクション</strong>：コードのコピー、セクションの移動などの操作</li><li><strong>検索履歴</strong>：サイト内で検索したキーワード</li></ul><h3 id="デバイス情報" tabindex="-1">デバイス情報 <a class="header-anchor" href="#デバイス情報" aria-label="Permalink to &quot;デバイス情報&quot;">​</a></h3><ul><li><strong>ブラウザ種別</strong>：Chrome、Firefox、Safari など</li><li><strong>オペレーティングシステム</strong>：Windows、macOS、Linux など</li><li><strong>IP アドレス</strong>：セキュリティ保護と地域最適化のために使用</li></ul><h2 id="_2-情報の使用目的" tabindex="-1">2. 情報の使用目的 <a class="header-anchor" href="#_2-情報の使用目的" aria-label="Permalink to &quot;2. 情報の使用目的&quot;">​</a></h2><p>収集した情報は以下の目的で使用します。</p><ul><li><strong>サービス提供</strong>：チュートリアルコンテンツへのアクセスと利用を保証</li><li><strong>パーソナライズ</strong>：閲覧進捗と設定を記憶</li><li><strong>製品改善</strong>：使用パターンを分析し、コンテンツと機能を最適化</li><li><strong>セキュリティ保障</strong>：異常な動作を検知し、悪用を防止</li><li><strong>通知送信</strong>：チュートリアルの更新通知や重要なお知らせを送信（配信停止可能）</li></ul><h2 id="_3-情報の共有と開示" tabindex="-1">3. 情報の共有と開示 <a class="header-anchor" href="#_3-情報の共有と開示" aria-label="Permalink to &quot;3. 情報の共有と開示&quot;">​</a></h2><p>お客様の個人情報を販売することはありません。以下の場合のみ共有する可能性があります。</p><ul><li><strong>第三者サービスプロバイダー</strong>：Vercel（ホスティング）、Plausible（分析）など。業務遂行に必要な情報のみアクセス可能</li><li><strong>法的要件</strong>：法規制や政府機関の要求に基づく開示</li><li><strong>権利保護</strong>：OpenCodeDocs およびユーザーの権利を保護するための必要な場合</li></ul><h2 id="_4-データの保存とセキュリティ" tabindex="-1">4. データの保存とセキュリティ <a class="header-anchor" href="#_4-データの保存とセキュリティ" aria-label="Permalink to &quot;4. データの保存とセキュリティ&quot;">​</a></h2><ul><li><strong>保存場所</strong>：米国およびアジア太平洋地域の安全なサーバーに保存</li><li><strong>暗号化措置</strong>：データ転送には TLS/SSL 暗号化、機密データには AES-256 暗号化を使用</li><li><strong>アクセス制御</strong>：内部スタッフのデータアクセス権限を厳格に制限</li><li><strong>保存期間</strong>：アカウント削除後、個人情報は 30 日以内に削除されます</li></ul><h2 id="_5-あなたの権利" tabindex="-1">5. あなたの権利 <a class="header-anchor" href="#_5-あなたの権利" aria-label="Permalink to &quot;5. あなたの権利&quot;">​</a></h2><p>「個人情報保護法」および GDPR に基づき、以下の権利を有します。</p><ul><li><strong>アクセス権</strong>：当社が保持する個人情報を閲覧する権利</li><li><strong>訂正権</strong>：不正確な個人情報の訂正を要求する権利</li><li><strong>削除権</strong>：個人情報の削除を要求する権利</li><li><strong>移転権</strong>：データを一般的な形式でエクスポートする権利</li><li><strong>同意の撤回</strong>：これまでに与えた同意をいつでも撤回する権利</li></ul><p>上記の権利を行使する場合は、以下の連絡先からご連絡ください。</p><h2 id="_6-cookie-ポリシー" tabindex="-1">6. Cookie ポリシー <a class="header-anchor" href="#_6-cookie-ポリシー" aria-label="Permalink to &quot;6. Cookie ポリシー&quot;">​</a></h2><p>以下の種類の Cookie を使用しています。</p><ul><li><strong>必須 Cookie</strong>：ログイン状態の維持、言語設定の記憶</li><li><strong>解析 Cookie</strong>：アクセス数と使用パターンの統計（プライバシーに配慮した Plausible を使用）</li><li><strong>広告 Cookie</strong>： <ul><li>第三者プロバイダー（Google を含む）は、Cookie を使用して、ユーザーがあなたのウェブサイトや他のウェブサイトで過去にアクセスした履歴に基づいて広告を配信します。</li><li>Google は、ユーザーがあなたのウェブサイトや/またはインターネット上の他のウェブサイトへのアクセス履歴に基づいて、ユーザーに広告を配信できるよう、Google およびそのパートナーが広告 Cookie を使用できるようにしています。</li><li>ユーザーは、<a href="https://www.google.com/settings/ads" target="_blank" rel="noreferrer">Google 広告設定</a> にアクセスしてパーソナライズされた広告を無効にすることができます。また、ユーザーを <a href="http://www.aboutads.info/choices/" target="_blank" rel="noreferrer">www.aboutads.info</a> に誘導して、パーソナライズされた広告に使用される第三者プロバイダーの Cookie を無効にすることもできます。</li></ul></li></ul><p>ブラウザ設定で Cookie を管理できます。必須 Cookie を無効にすると、一部の機能が正常に動作しない場合があります。</p><h2 id="_7-お問い合わせ" tabindex="-1">7. お問い合わせ <a class="header-anchor" href="#_7-お問い合わせ" aria-label="Permalink to &quot;7. お問い合わせ&quot;">​</a></h2><p>本プライバシーポリシーに関するご質問や、データに関する権利の行使をご希望の場合は、以下までご連絡ください。</p><ul><li><strong>メール</strong>：<a href="mailto:vbgatecom@gmail.com" target="_blank" rel="noreferrer">vbgatecom@gmail.com</a></li><li><strong>応答時間</strong>：ご要請に対して 15 営業日以内にご返信いたします</li></ul>',30)])])}const p=a(t,[["render",e]]);export{u as __pageData,p as default};
